-- ── Culinse eigener Rezept-Korpus: Seed ──────────────────────────────────────
-- AUTOMATISCH ERZEUGT von build_seed.py — nicht von Hand editieren.
-- Quelle: recipes.json · Rezepte: 8 × 2 Sprachen = 16 Zeilen
-- Bilder: 8/8 Rezepte mit Foto (alle als Entwurf).
--
-- Reihenfolge: ZUERST 00_add_language.sql, DANN diese Datei (Supabase SQL Editor).
-- nutrition ist vorausgefüllt → KEINE Spoonacular-Berechnung beim ersten Aufruf.

DO $seed$
DECLARE
  v_author uuid;
BEGIN
  SELECT id INTO v_author
  FROM auth.users
  WHERE lower(email) = lower('peter@hoelzer.xyz')
  LIMIT 1;

  IF v_author IS NULL THEN
    RAISE EXCEPTION 'Kein Nutzer mit E-Mail % gefunden — author_email in recipes.json anpassen und neu generieren.', 'peter@hoelzer.xyz';
  END IF;

  INSERT INTO user_recipes (
    user_id, language, translation_group, title, description, image_url, image_position, video_url, ingredients, instructions, cook_time, prep_time, servings, tags, status, is_public, source_type, source_name, nutrition, created_at, updated_at
  )
  VALUES
    (v_author, 'de', 'tomaten-linsen-suppe', 'Cremige Tomaten-Linsen-Suppe', 'Sämige, wärmende Suppe aus roten Linsen und Tomaten, mit einem Schuss Kokosmilch abgerundet. In 35 Minuten fertig, komplett pflanzlich und alltagstauglich.', 'https://ztfhnzslyztxfmvkyrrn.supabase.co/storage/v1/object/public/recipe-media/5518f1b2-455e-4ee3-8a38-85ad8e16a064/seed/tomaten-linsen-suppe.jpg', '50% 50%', NULL, '[{"amount":"200","unit":"g","name":"rote Linsen"},{"amount":"800","unit":"g","name":"gehackte Tomaten (aus der Dose)"},{"amount":"1","unit":"Stück","name":"Zwiebel"},{"amount":"2","unit":"Zehen","name":"Knoblauch"},{"amount":"30","unit":"ml","name":"Olivenöl"},{"amount":"750","unit":"ml","name":"Gemüsebrühe"},{"amount":"200","unit":"ml","name":"Kokosmilch"},{"amount":"1","unit":"Prise","name":"Kreuzkümmel, gemahlen"},{"amount":"1","unit":"Prise","name":"Salz und Pfeffer"}]'::jsonb, '[{"step":1,"text":"Zwiebel und Knoblauch fein würfeln. Olivenöl in einem Topf erhitzen und beides bei mittlerer Hitze 3 Minuten glasig dünsten.","timer_minutes":3},{"step":2,"text":"Kreuzkümmel kurz mitrösten, dann die roten Linsen einrühren.","timer_minutes":null},{"step":3,"text":"Gehackte Tomaten und Gemüsebrühe zugeben, aufkochen und zugedeckt 20 Minuten köcheln, bis die Linsen weich sind.","timer_minutes":20},{"step":4,"text":"Suppe mit dem Stabmixer fein pürieren, Kokosmilch unterrühren und mit Salz und Pfeffer abschmecken.","timer_minutes":null}]'::jsonb, 25, 10, 4, '{"vegan","suppe","schnell","einfach","linsen","meal-prep"}'::text[], 'draft', false, 'created', 'Culinse', '{"calories":320,"protein":14,"fat":13,"carbs":38}'::jsonb, now(), now()),
    (v_author, 'en', 'tomaten-linsen-suppe', 'Creamy Tomato Lentil Soup', 'A silky, warming soup of red lentils and tomatoes, finished with a splash of coconut milk. Ready in 35 minutes, fully plant-based and perfect for everyday cooking.', 'https://ztfhnzslyztxfmvkyrrn.supabase.co/storage/v1/object/public/recipe-media/5518f1b2-455e-4ee3-8a38-85ad8e16a064/seed/tomaten-linsen-suppe.jpg', '50% 50%', NULL, '[{"amount":"200","unit":"g","name":"red lentils"},{"amount":"800","unit":"g","name":"chopped tomatoes (canned)"},{"amount":"1","unit":"piece","name":"onion"},{"amount":"2","unit":"cloves","name":"garlic"},{"amount":"30","unit":"ml","name":"olive oil"},{"amount":"750","unit":"ml","name":"vegetable stock"},{"amount":"200","unit":"ml","name":"coconut milk"},{"amount":"1","unit":"pinch","name":"ground cumin"},{"amount":"1","unit":"pinch","name":"salt and pepper"}]'::jsonb, '[{"step":1,"text":"Finely dice the onion and garlic. Heat the olive oil in a pot and sweat both over medium heat for 3 minutes until translucent.","timer_minutes":3},{"step":2,"text":"Toast the cumin briefly, then stir in the red lentils.","timer_minutes":null},{"step":3,"text":"Add the chopped tomatoes and vegetable stock, bring to a boil and simmer covered for 20 minutes until the lentils are soft.","timer_minutes":20},{"step":4,"text":"Blend the soup smooth with an immersion blender, stir in the coconut milk and season with salt and pepper.","timer_minutes":null}]'::jsonb, 25, 10, 4, '{"vegan","soup","quick","easy","lentils","meal-prep"}'::text[], 'draft', false, 'created', 'Culinse', '{"calories":320,"protein":14,"fat":13,"carbs":38}'::jsonb, now(), now()),
    (v_author, 'de', 'spaghetti-carbonara', 'Klassische Spaghetti Carbonara', 'Die echte römische Carbonara — ohne Sahne. Cremig wird sie nur durch Eigelb, Pecorino und das stärkehaltige Nudelwasser. Knuspriger Guanciale gibt den Biss.', 'https://ztfhnzslyztxfmvkyrrn.supabase.co/storage/v1/object/public/recipe-media/5518f1b2-455e-4ee3-8a38-85ad8e16a064/seed/spaghetti-carbonara.jpg', '50% 50%', NULL, '[{"amount":"400","unit":"g","name":"Spaghetti"},{"amount":"150","unit":"g","name":"Guanciale (oder Pancetta)"},{"amount":"4","unit":"Stück","name":"Eigelb"},{"amount":"1","unit":"Stück","name":"Ei"},{"amount":"100","unit":"g","name":"Pecorino Romano, gerieben"},{"amount":"1","unit":"Prise","name":"schwarzer Pfeffer, frisch gemahlen"}]'::jsonb, '[{"step":1,"text":"Spaghetti in reichlich Salzwasser nach Packungsangabe al dente kochen. Eine Tasse Nudelwasser aufheben.","timer_minutes":10},{"step":2,"text":"Guanciale würfeln und in einer Pfanne ohne Öl bei mittlerer Hitze knusprig auslassen.","timer_minutes":6},{"step":3,"text":"Eigelb, Ei und Pecorino mit viel Pfeffer in einer Schüssel glatt verrühren.","timer_minutes":null},{"step":4,"text":"Abgegossene heiße Spaghetti zum Guanciale geben, vom Herd nehmen, Ei-Käse-Mischung unterrühren und mit etwas Nudelwasser zu einer cremigen Sauce binden.","timer_minutes":null}]'::jsonb, 15, 10, 4, '{"italienisch","pasta","schnell","klassiker"}'::text[], 'draft', false, 'created', 'Culinse', '{"calories":650,"protein":28,"fat":26,"carbs":75}'::jsonb, now(), now()),
    (v_author, 'en', 'spaghetti-carbonara', 'Classic Spaghetti Carbonara', 'The real Roman carbonara — no cream. It turns creamy from egg yolks, Pecorino and starchy pasta water alone. Crispy guanciale gives it the bite.', 'https://ztfhnzslyztxfmvkyrrn.supabase.co/storage/v1/object/public/recipe-media/5518f1b2-455e-4ee3-8a38-85ad8e16a064/seed/spaghetti-carbonara.jpg', '50% 50%', NULL, '[{"amount":"400","unit":"g","name":"spaghetti"},{"amount":"150","unit":"g","name":"guanciale (or pancetta)"},{"amount":"4","unit":"piece","name":"egg yolks"},{"amount":"1","unit":"piece","name":"egg"},{"amount":"100","unit":"g","name":"Pecorino Romano, grated"},{"amount":"1","unit":"pinch","name":"black pepper, freshly ground"}]'::jsonb, '[{"step":1,"text":"Cook the spaghetti al dente in plenty of salted water per the package. Reserve a cup of pasta water.","timer_minutes":10},{"step":2,"text":"Dice the guanciale and render it crisp in a dry pan over medium heat.","timer_minutes":6},{"step":3,"text":"Whisk the egg yolks, egg and Pecorino with plenty of pepper in a bowl until smooth.","timer_minutes":null},{"step":4,"text":"Add the drained hot spaghetti to the guanciale, take off the heat, stir in the egg-cheese mix and loosen with a little pasta water into a creamy sauce.","timer_minutes":null}]'::jsonb, 15, 10, 4, '{"italian","pasta","quick","classic"}'::text[], 'draft', false, 'created', 'Culinse', '{"calories":650,"protein":28,"fat":26,"carbs":75}'::jsonb, now(), now()),
    (v_author, 'de', 'haehnchen-kokos-curry', 'Hähnchen-Kokos-Curry', 'Schnelles thailändisch inspiriertes Curry mit zartem Hähnchen, Paprika und cremiger Kokosmilch. Schön scharf, in einer halben Stunde auf dem Tisch.', 'https://ztfhnzslyztxfmvkyrrn.supabase.co/storage/v1/object/public/recipe-media/5518f1b2-455e-4ee3-8a38-85ad8e16a064/seed/haehnchen-kokos-curry.jpg', '50% 50%', NULL, '[{"amount":"600","unit":"g","name":"Hähnchenbrustfilet"},{"amount":"400","unit":"ml","name":"Kokosmilch"},{"amount":"30","unit":"g","name":"rote Currypaste"},{"amount":"200","unit":"g","name":"Paprika"},{"amount":"150","unit":"g","name":"Zwiebel"},{"amount":"30","unit":"ml","name":"Pflanzenöl"},{"amount":"1","unit":"Bund","name":"Koriander"},{"amount":"1","unit":"Prise","name":"Salz"}]'::jsonb, '[{"step":1,"text":"Hähnchen in mundgerechte Streifen schneiden. Zwiebel in Spalten, Paprika in Streifen schneiden.","timer_minutes":null},{"step":2,"text":"Öl in einer tiefen Pfanne erhitzen, Currypaste 1 Minute anrösten, bis sie duftet.","timer_minutes":1},{"step":3,"text":"Hähnchen zugeben und bei hoher Hitze rundum anbraten, dann Zwiebel und Paprika 3 Minuten mitbraten.","timer_minutes":5},{"step":4,"text":"Mit Kokosmilch ablöschen und 12 Minuten köcheln, bis die Sauce leicht eindickt. Mit Salz abschmecken und mit Koriander bestreuen.","timer_minutes":12}]'::jsonb, 20, 15, 4, '{"asiatisch","hähnchen","curry","schnell","glutenfrei"}'::text[], 'draft', false, 'created', 'Culinse', '{"calories":420,"protein":38,"fat":25,"carbs":12}'::jsonb, now(), now()),
    (v_author, 'en', 'haehnchen-kokos-curry', 'Chicken Coconut Curry', 'A fast Thai-inspired curry with tender chicken, bell pepper and creamy coconut milk. Nicely spicy and on the table in half an hour.', 'https://ztfhnzslyztxfmvkyrrn.supabase.co/storage/v1/object/public/recipe-media/5518f1b2-455e-4ee3-8a38-85ad8e16a064/seed/haehnchen-kokos-curry.jpg', '50% 50%', NULL, '[{"amount":"600","unit":"g","name":"chicken breast"},{"amount":"400","unit":"ml","name":"coconut milk"},{"amount":"30","unit":"g","name":"red curry paste"},{"amount":"200","unit":"g","name":"bell pepper"},{"amount":"150","unit":"g","name":"onion"},{"amount":"30","unit":"ml","name":"vegetable oil"},{"amount":"1","unit":"bunch","name":"cilantro"},{"amount":"1","unit":"pinch","name":"salt"}]'::jsonb, '[{"step":1,"text":"Cut the chicken into bite-sized strips. Cut the onion into wedges and the bell pepper into strips.","timer_minutes":null},{"step":2,"text":"Heat the oil in a deep pan and fry the curry paste for 1 minute until fragrant.","timer_minutes":1},{"step":3,"text":"Add the chicken and sear over high heat, then add the onion and pepper and cook for 3 minutes.","timer_minutes":5},{"step":4,"text":"Deglaze with coconut milk and simmer for 12 minutes until the sauce thickens slightly. Season with salt and scatter with cilantro.","timer_minutes":12}]'::jsonb, 20, 15, 4, '{"asian","chicken","curry","quick","gluten-free"}'::text[], 'draft', false, 'created', 'Culinse', '{"calories":420,"protein":38,"fat":25,"carbs":12}'::jsonb, now(), now()),
    (v_author, 'de', 'kartoffel-gemuese-auflauf', 'Kartoffel-Gemüse-Auflauf', 'Herzhafter Ofenauflauf mit Kartoffeln, Zucchini und einer goldenen Käsekruste. Ein vegetarischer Klassiker für die ganze Familie.', 'https://ztfhnzslyztxfmvkyrrn.supabase.co/storage/v1/object/public/recipe-media/5518f1b2-455e-4ee3-8a38-85ad8e16a064/seed/kartoffel-gemuese-auflauf.jpg', '50% 50%', NULL, '[{"amount":"800","unit":"g","name":"festkochende Kartoffeln"},{"amount":"300","unit":"g","name":"Zucchini"},{"amount":"200","unit":"ml","name":"Sahne"},{"amount":"150","unit":"g","name":"geriebener Käse (z. B. Gouda)"},{"amount":"1","unit":"Stück","name":"Zwiebel"},{"amount":"1","unit":"Zehe","name":"Knoblauch"},{"amount":"1","unit":"Prise","name":"Muskatnuss"},{"amount":"1","unit":"Prise","name":"Salz und Pfeffer"}]'::jsonb, '[{"step":1,"text":"Backofen auf 200 °C Ober-/Unterhitze vorheizen. Kartoffeln und Zucchini in dünne Scheiben, Zwiebel in Ringe schneiden.","timer_minutes":null},{"step":2,"text":"Gemüse abwechselnd in eine gefettete Auflaufform schichten und jede Lage leicht salzen und pfeffern.","timer_minutes":null},{"step":3,"text":"Sahne mit gepresstem Knoblauch und Muskatnuss verrühren und gleichmäßig über das Gemüse gießen.","timer_minutes":null},{"step":4,"text":"Mit Käse bestreuen und im Ofen 40 Minuten goldbraun backen.","timer_minutes":40}]'::jsonb, 40, 20, 4, '{"vegetarisch","auflauf","ofengericht","kartoffeln","familienküche"}'::text[], 'draft', false, 'created', 'Culinse', '{"calories":410,"protein":14,"fat":22,"carbs":38}'::jsonb, now(), now()),
    (v_author, 'en', 'kartoffel-gemuese-auflauf', 'Potato and Vegetable Bake', 'A hearty oven bake with potatoes, zucchini and a golden cheese crust. A vegetarian classic the whole family will love.', 'https://ztfhnzslyztxfmvkyrrn.supabase.co/storage/v1/object/public/recipe-media/5518f1b2-455e-4ee3-8a38-85ad8e16a064/seed/kartoffel-gemuese-auflauf.jpg', '50% 50%', NULL, '[{"amount":"800","unit":"g","name":"waxy potatoes"},{"amount":"300","unit":"g","name":"zucchini"},{"amount":"200","unit":"ml","name":"cream"},{"amount":"150","unit":"g","name":"grated cheese (e.g. Gouda)"},{"amount":"1","unit":"piece","name":"onion"},{"amount":"1","unit":"clove","name":"garlic"},{"amount":"1","unit":"pinch","name":"nutmeg"},{"amount":"1","unit":"pinch","name":"salt and pepper"}]'::jsonb, '[{"step":1,"text":"Preheat the oven to 200 °C (top/bottom heat). Slice the potatoes and zucchini thinly and cut the onion into rings.","timer_minutes":null},{"step":2,"text":"Layer the vegetables alternately in a greased baking dish, lightly salting and peppering each layer.","timer_minutes":null},{"step":3,"text":"Mix the cream with the pressed garlic and nutmeg and pour it evenly over the vegetables.","timer_minutes":null},{"step":4,"text":"Sprinkle with cheese and bake in the oven for 40 minutes until golden.","timer_minutes":40}]'::jsonb, 40, 20, 4, '{"vegetarian","casserole","oven-baked","potatoes","family-friendly"}'::text[], 'draft', false, 'created', 'Culinse', '{"calories":410,"protein":14,"fat":22,"carbs":38}'::jsonb, now(), now()),
    (v_author, 'de', 'rindergulasch', 'Klassisches Rindergulasch', 'Geduldig geschmortes Rindergulasch, bei dem die Zwiebeln fast die gleiche Menge wie das Fleisch ausmachen — das Geheimnis der samtigen Sauce. Wird mit der Zeit nur besser.', 'https://ztfhnzslyztxfmvkyrrn.supabase.co/storage/v1/object/public/recipe-media/5518f1b2-455e-4ee3-8a38-85ad8e16a064/seed/rindergulasch.jpg', '50% 50%', NULL, '[{"amount":"800","unit":"g","name":"Rindergulasch (aus der Schulter)"},{"amount":"400","unit":"g","name":"Zwiebeln"},{"amount":"200","unit":"g","name":"rote Paprika"},{"amount":"30","unit":"g","name":"Paprikapulver edelsüß"},{"amount":"30","unit":"ml","name":"Pflanzenöl"},{"amount":"500","unit":"ml","name":"Rinderbrühe"},{"amount":"15","unit":"g","name":"Tomatenmark"},{"amount":"1","unit":"Prise","name":"Salz und Pfeffer"}]'::jsonb, '[{"step":1,"text":"Fleisch trockentupfen und in einem schweren Topf im heißen Öl portionsweise kräftig anbraten, herausnehmen.","timer_minutes":8},{"step":2,"text":"Zwiebeln in Streifen im selben Topf goldbraun braten. Tomatenmark und Paprikapulver kurz mitrösten (nicht verbrennen lassen).","timer_minutes":8},{"step":3,"text":"Fleisch zurückgeben, mit Rinderbrühe ablöschen und zugedeckt bei niedriger Hitze 90 Minuten schmoren.","timer_minutes":90},{"step":4,"text":"Paprika in Stücken zugeben und weitere 30 Minuten schmoren, bis das Fleisch zart ist. Mit Salz und Pfeffer abschmecken.","timer_minutes":30}]'::jsonb, 120, 20, 4, '{"rindfleisch","schmorgericht","deftig","hausmannskost","glutenfrei"}'::text[], 'draft', false, 'created', 'Culinse', '{"calories":480,"protein":45,"fat":26,"carbs":14}'::jsonb, now(), now()),
    (v_author, 'en', 'rindergulasch', 'Classic Beef Goulash', 'A patiently braised beef goulash where the onions almost match the meat by weight — the secret to its velvety sauce. It only gets better with time.', 'https://ztfhnzslyztxfmvkyrrn.supabase.co/storage/v1/object/public/recipe-media/5518f1b2-455e-4ee3-8a38-85ad8e16a064/seed/rindergulasch.jpg', '50% 50%', NULL, '[{"amount":"800","unit":"g","name":"beef goulash (chuck)"},{"amount":"400","unit":"g","name":"onions"},{"amount":"200","unit":"g","name":"red bell pepper"},{"amount":"30","unit":"g","name":"sweet paprika powder"},{"amount":"30","unit":"ml","name":"vegetable oil"},{"amount":"500","unit":"ml","name":"beef stock"},{"amount":"15","unit":"g","name":"tomato paste"},{"amount":"1","unit":"pinch","name":"salt and pepper"}]'::jsonb, '[{"step":1,"text":"Pat the meat dry and sear it hard in batches in hot oil in a heavy pot, then remove.","timer_minutes":8},{"step":2,"text":"Fry the sliced onions golden in the same pot. Add the tomato paste and paprika powder and toast briefly (do not let it burn).","timer_minutes":8},{"step":3,"text":"Return the meat, deglaze with beef stock and braise covered over low heat for 90 minutes.","timer_minutes":90},{"step":4,"text":"Add the chopped bell pepper and braise another 30 minutes until the meat is tender. Season with salt and pepper.","timer_minutes":30}]'::jsonb, 120, 20, 4, '{"beef","stew","hearty","comfort-food","gluten-free"}'::text[], 'draft', false, 'created', 'Culinse', '{"calories":480,"protein":45,"fat":26,"carbs":14}'::jsonb, now(), now()),
    (v_author, 'de', 'overnight-oats-beeren', 'Overnight Oats mit Beeren', 'Über Nacht eingeweichte Haferflocken mit Joghurt, Chiasamen und frischen Beeren. Am Abend in 10 Minuten vorbereitet, morgens sofort löffelfertig.', 'https://ztfhnzslyztxfmvkyrrn.supabase.co/storage/v1/object/public/recipe-media/5518f1b2-455e-4ee3-8a38-85ad8e16a064/seed/overnight-oats-beeren.jpg', '50% 50%', NULL, '[{"amount":"100","unit":"g","name":"Haferflocken"},{"amount":"250","unit":"ml","name":"Milch"},{"amount":"150","unit":"g","name":"Naturjoghurt"},{"amount":"150","unit":"g","name":"gemischte Beeren"},{"amount":"20","unit":"g","name":"Honig"},{"amount":"20","unit":"g","name":"Chiasamen"}]'::jsonb, '[{"step":1,"text":"Haferflocken, Chiasamen, Milch und Joghurt in einer Schüssel oder zwei Gläsern gut verrühren.","timer_minutes":null},{"step":2,"text":"Honig unterrühren, abdecken und über Nacht (mindestens 6 Stunden) in den Kühlschrank stellen.","timer_minutes":null},{"step":3,"text":"Am Morgen umrühren; bei Bedarf mit einem Schuss Milch lockern.","timer_minutes":null},{"step":4,"text":"Mit frischen Beeren toppen und servieren.","timer_minutes":null}]'::jsonb, 0, 10, 2, '{"frühstück","vegetarisch","meal-prep","ohne kochen","schnell"}'::text[], 'draft', false, 'created', 'Culinse', '{"calories":380,"protein":16,"fat":11,"carbs":55}'::jsonb, now(), now()),
    (v_author, 'en', 'overnight-oats-beeren', 'Overnight Oats with Berries', 'Rolled oats soaked overnight with yogurt, chia seeds and fresh berries. Prepped in 10 minutes the night before, ready to spoon in the morning.', 'https://ztfhnzslyztxfmvkyrrn.supabase.co/storage/v1/object/public/recipe-media/5518f1b2-455e-4ee3-8a38-85ad8e16a064/seed/overnight-oats-beeren.jpg', '50% 50%', NULL, '[{"amount":"100","unit":"g","name":"rolled oats"},{"amount":"250","unit":"ml","name":"milk"},{"amount":"150","unit":"g","name":"plain yogurt"},{"amount":"150","unit":"g","name":"mixed berries"},{"amount":"20","unit":"g","name":"honey"},{"amount":"20","unit":"g","name":"chia seeds"}]'::jsonb, '[{"step":1,"text":"Stir the oats, chia seeds, milk and yogurt together well in a bowl or two jars.","timer_minutes":null},{"step":2,"text":"Mix in the honey, cover and refrigerate overnight (at least 6 hours).","timer_minutes":null},{"step":3,"text":"In the morning, stir; loosen with a splash of milk if needed.","timer_minutes":null},{"step":4,"text":"Top with fresh berries and serve.","timer_minutes":null}]'::jsonb, 0, 10, 2, '{"breakfast","vegetarian","meal-prep","no-cook","quick"}'::text[], 'draft', false, 'created', 'Culinse', '{"calories":380,"protein":16,"fat":11,"carbs":55}'::jsonb, now(), now()),
    (v_author, 'de', 'falafel-bowl-tahini', 'Falafel-Bowl mit Tahini-Dressing', 'Knusprige selbstgemachte Falafel aus Kichererbsen auf einer frischen Bowl mit Tomaten und Gurke, übergossen mit cremigem Tahini-Dressing. Komplett pflanzlich und sättigend.', 'https://ztfhnzslyztxfmvkyrrn.supabase.co/storage/v1/object/public/recipe-media/5518f1b2-455e-4ee3-8a38-85ad8e16a064/seed/falafel-bowl-tahini.jpg', '50% 50%', NULL, '[{"amount":"480","unit":"g","name":"Kichererbsen (gekocht, abgetropft)"},{"amount":"1","unit":"Stück","name":"Zwiebel"},{"amount":"2","unit":"Zehen","name":"Knoblauch"},{"amount":"1","unit":"Bund","name":"glatte Petersilie"},{"amount":"30","unit":"g","name":"Mehl"},{"amount":"60","unit":"g","name":"Tahini (Sesammus)"},{"amount":"200","unit":"g","name":"Tomaten"},{"amount":"200","unit":"g","name":"Gurke"},{"amount":"30","unit":"ml","name":"Olivenöl"},{"amount":"1","unit":"Prise","name":"Kreuzkümmel, Salz und Pfeffer"}]'::jsonb, '[{"step":1,"text":"Kichererbsen, Zwiebel, Knoblauch, Petersilie, Mehl und Gewürze in einer Küchenmaschine zu einer grobkörnigen Masse zerkleinern (nicht zu fein).","timer_minutes":null},{"step":2,"text":"Aus der Masse mit feuchten Händen etwa 16 kleine Bällchen formen.","timer_minutes":null},{"step":3,"text":"Olivenöl in einer Pfanne erhitzen und die Falafel rundum 15 Minuten goldbraun und knusprig braten.","timer_minutes":15},{"step":4,"text":"Tahini mit 60 ml Wasser, Salz und einem Spritzer Zitrone glattrühren. Tomaten und Gurke würfeln, alles in Schalen anrichten und mit Dressing beträufeln.","timer_minutes":null}]'::jsonb, 15, 25, 4, '{"vegan","mediterran","bowl","kichererbsen","meal-prep"}'::text[], 'draft', false, 'created', 'Culinse', '{"calories":450,"protein":18,"fat":21,"carbs":48}'::jsonb, now(), now()),
    (v_author, 'en', 'falafel-bowl-tahini', 'Falafel Bowl with Tahini Dressing', 'Crispy homemade chickpea falafel over a fresh bowl with tomatoes and cucumber, drizzled with creamy tahini dressing. Fully plant-based and filling.', 'https://ztfhnzslyztxfmvkyrrn.supabase.co/storage/v1/object/public/recipe-media/5518f1b2-455e-4ee3-8a38-85ad8e16a064/seed/falafel-bowl-tahini.jpg', '50% 50%', NULL, '[{"amount":"480","unit":"g","name":"chickpeas (cooked, drained)"},{"amount":"1","unit":"piece","name":"onion"},{"amount":"2","unit":"cloves","name":"garlic"},{"amount":"1","unit":"bunch","name":"flat-leaf parsley"},{"amount":"30","unit":"g","name":"flour"},{"amount":"60","unit":"g","name":"tahini (sesame paste)"},{"amount":"200","unit":"g","name":"tomatoes"},{"amount":"200","unit":"g","name":"cucumber"},{"amount":"30","unit":"ml","name":"olive oil"},{"amount":"1","unit":"pinch","name":"cumin, salt and pepper"}]'::jsonb, '[{"step":1,"text":"Pulse the chickpeas, onion, garlic, parsley, flour and spices in a food processor into a coarse mixture (not too fine).","timer_minutes":null},{"step":2,"text":"With damp hands, shape the mixture into about 16 small balls.","timer_minutes":null},{"step":3,"text":"Heat the olive oil in a pan and fry the falafel for 15 minutes until golden and crisp all over.","timer_minutes":15},{"step":4,"text":"Whisk the tahini with 60 ml water, salt and a squeeze of lemon until smooth. Dice the tomatoes and cucumber, arrange everything in bowls and drizzle with dressing.","timer_minutes":null}]'::jsonb, 15, 25, 4, '{"vegan","mediterranean","bowl","chickpeas","meal-prep"}'::text[], 'draft', false, 'created', 'Culinse', '{"calories":450,"protein":18,"fat":21,"carbs":48}'::jsonb, now(), now()),
    (v_author, 'de', 'lachs-honig-senf-kruste', 'Lachs mit Honig-Senf-Kruste', 'Saftiges Lachsfilet aus dem Ofen unter einer glänzenden Honig-Senf-Glasur mit Dill. Festtagsverdächtig, aber in 25 Minuten gemacht.', 'https://ztfhnzslyztxfmvkyrrn.supabase.co/storage/v1/object/public/recipe-media/5518f1b2-455e-4ee3-8a38-85ad8e16a064/seed/lachs-honig-senf-kruste.jpg', '50% 50%', NULL, '[{"amount":"600","unit":"g","name":"Lachsfilet (mit Haut)"},{"amount":"40","unit":"g","name":"mittelscharfer Senf"},{"amount":"30","unit":"g","name":"Honig"},{"amount":"30","unit":"ml","name":"Olivenöl"},{"amount":"1","unit":"Bund","name":"Dill"},{"amount":"1","unit":"Stück","name":"Zitrone"},{"amount":"1","unit":"Prise","name":"Salz und Pfeffer"}]'::jsonb, '[{"step":1,"text":"Backofen auf 200 °C vorheizen. Lachs trockentupfen, salzen, pfeffern und mit der Haut nach unten auf ein mit Backpapier belegtes Blech legen.","timer_minutes":null},{"step":2,"text":"Senf, Honig, Olivenöl und gehackten Dill zu einer Glasur verrühren.","timer_minutes":null},{"step":3,"text":"Glasur gleichmäßig auf dem Lachs verstreichen.","timer_minutes":null},{"step":4,"text":"Im Ofen 15 Minuten backen, bis der Lachs glasig gar ist. Mit Zitronenspalten servieren.","timer_minutes":15}]'::jsonb, 15, 10, 4, '{"fisch","lachs","schnell","proteinreich","ofengericht"}'::text[], 'draft', false, 'created', 'Culinse', '{"calories":400,"protein":34,"fat":24,"carbs":12}'::jsonb, now(), now()),
    (v_author, 'en', 'lachs-honig-senf-kruste', 'Salmon with Honey Mustard Crust', 'Juicy oven-baked salmon fillet under a glossy honey-mustard glaze with dill. Looks special-occasion, but ready in 25 minutes.', 'https://ztfhnzslyztxfmvkyrrn.supabase.co/storage/v1/object/public/recipe-media/5518f1b2-455e-4ee3-8a38-85ad8e16a064/seed/lachs-honig-senf-kruste.jpg', '50% 50%', NULL, '[{"amount":"600","unit":"g","name":"salmon fillet (skin on)"},{"amount":"40","unit":"g","name":"medium mustard"},{"amount":"30","unit":"g","name":"honey"},{"amount":"30","unit":"ml","name":"olive oil"},{"amount":"1","unit":"bunch","name":"dill"},{"amount":"1","unit":"piece","name":"lemon"},{"amount":"1","unit":"pinch","name":"salt and pepper"}]'::jsonb, '[{"step":1,"text":"Preheat the oven to 200 °C. Pat the salmon dry, season with salt and pepper and place skin-side down on a lined baking sheet.","timer_minutes":null},{"step":2,"text":"Mix the mustard, honey, olive oil and chopped dill into a glaze.","timer_minutes":null},{"step":3,"text":"Spread the glaze evenly over the salmon.","timer_minutes":null},{"step":4,"text":"Bake in the oven for 15 minutes until the salmon is just cooked through. Serve with lemon wedges.","timer_minutes":15}]'::jsonb, 15, 10, 4, '{"fish","salmon","quick","high-protein","oven-baked"}'::text[], 'draft', false, 'created', 'Culinse', '{"calories":400,"protein":34,"fat":24,"carbs":12}'::jsonb, now(), now());

  RAISE NOTICE '✓ 16 Seed-Rezepte für % angelegt.', 'peter@hoelzer.xyz';
